import numpy as np

def connected_component(image, threshold):
  # Initialize the mask
  mask = np.zeros_like(image)
  # Iterate over each pixel in the image
  for i in range(image.shape[0]):
    for j in range(image.shape[1]):
      # Check if the pixel is above the threshold
      if image[i, j] > threshold:
        # Set the pixel in the mask to 1
        mask[i, j] = 1
  # Return the mask
  return mask

#include <stdio.h>
#include <stdlib.h>

// Function to create a 2D array
int** createArray(int rows, int cols) {
  int** arr = (int**)malloc(rows * sizeof(int*));
  for (int i = 0; i < rows; i++) {
    arr[i] = (int*)malloc(cols * sizeof(int));
  }
  return arr;
}

// Function to free a 2D array
void freeArray(int** arr, int rows) {
  for (int i = 0; i < rows; i++) {
    free(arr[i]);
  }
  free(arr);
}

// Function to create a mask
int** connectedComponent(int** image, int threshold, int rows, int cols) {
  // Initialize the mask
  int** mask = createArray(rows, cols);
  // Iterate over each pixel in the image
  for (int i = 0; i < rows; i++) {
    for (int j = 0; j < cols; j++) {
      // Check if the pixel is above the threshold
      if (image[i][j] > threshold) {
        // Set the pixel in the mask to 1
        mask[i][j] = 1;
      } else {
        mask[i][j] = 0;
      }
    }
  }
  // Return the mask
  return mask;
}
